        # Health check
        server {
            listen 13129;
            access_log  off;
            # Health check endpoint
            location /healthz {
                add_header Content-Type text/plain;
                return 200 "The Container Caching Proxy is running!";
            }

            # reload nginx
            location /reload {
                allow 127.0.0.1;
                deny all;
                content_by_lua_block {
                    local resty_signal = require "resty.signal"
                    local file, err = io.open("/var/run/nginx.pid", "r")
                    if file == nil then
                        ngx.status = 500
                        ngx.say("Failed to reload nginx process: ", err)
                        ngx.exit(ngx.status)
                    end
                    local pid = file:read("*n")
                    file:close()
                    ngx.say("Nginx PID", pid)
                    ngx.say("Reloading nginx", pid)
                    local ok, err = resty_signal.kill(pid, "HUP")
                    if not ok then
                        ngx.log(ngx.ERR, "failed to reload nginx process of pid ", pid, ": ", err)
                        ngx.say("Failed to reload nginx process: ", err)
                        ngx.status = 500
                        ngx.exit(ngx.status)
                    end
                }
            }
        }

        # Metrics
        server {
            listen 9145;
            access_log off;
            location /cache_metrics {
                content_by_lua_block {
                    metric_connections:set(ngx.var.connections_reading, {"reading"})
                    metric_connections:set(ngx.var.connections_waiting, {"waiting"})
                    metric_connections:set(ngx.var.connections_writing, {"writing"})
                    prometheus:collect()
                }
            }

            location = /metrics {
                return 404;
            }

            location /nginx_status {
                stub_status on;
                allow 127.0.0.1;
                allow ::1;
                deny all;
            }
        }

